  // Register a plugin object with hooks
  registerPlugin(name, plugin) {
    if (this.plugins.has(name)) {
      console.warn(`[PluginManager] Plugin "${name}" is already registered. Overwriting.`);
    }

    this.plugins.set(name, plugin);
    this.pluginOrder.push(name);

    // Register hooks
    for (const hookName of Object.keys(this.hooks)) {
      if (typeof plugin[hookName] === 'function') {
        this.hooks[hookName].push({
          name,
          handler: plugin[hookName].bind(plugin),
          priority: plugin.priority || 0,
        });
        // Sort by priority (higher priority runs first)
        this.hooks[hookName].sort((a, b) => b.priority - a.priority);
      }
    }

    console.log(`[PluginManager] Plugin "${name}" registered successfully.`);
    return plugin;
  }

