// Example: Rate Limiter Plugin (inline code)
const rateLimiterPluginCode = `
const requests = new Map();

module.exports = {
  name: 'rate-limiter',
  version: '1.0.0',
  description: 'Simple in-memory rate limiter',
  priority: 100,

  onRequest: async (context) => {
    const ip = context.req.socket.remoteAddress;
    const limit = pluginOptions.limit || 100;
    const windowMs = pluginOptions.windowMs || 60000;

    const now = Date.now();
    const record = requests.get(ip) || { count: 0, resetTime: now + windowMs };

    if (now > record.resetTime) {
      record.count = 0;
      record.resetTime = now + windowMs;
    }

    record.count++;
    requests.set(ip, record);

    if (record.count > limit) {
      context.skipProxy = true;
      context.responseStatusCode = 429;
      context.responseHeaders = { 'Content-Type': 'application/json', 'Retry-After': String(Math.ceil((record.resetTime - now) / 1000)) };
      context.responseBody = JSON.stringify({ error: 'Too Many Requests', retryAfter: Math.ceil((record.resetTime - now) / 1000) });
      return false;
    }

    context.responseHeaders['X-RateLimit-Limit'] = String(limit);
    context.responseHeaders['X-RateLimit-Remaining'] = String(limit - record.count);
  }
};
`;

